-- 4.3.1 Отдел мониторинга операций клиентов физических лиц
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.3.1'
  FROM (VALUES
    ('Обеспечение своевременного выявления, квалификации и формирования сообщений по подозрительным операциям (сделкам) клиентов – физических лиц, связанным с легализацией (отмыванием) доходов, полученных преступным путём, или финансированием терроризма, совокупности подозрительных операций и (или) действий, в том числе при осуществлении Банком профессиональной деятельности на рынке ценных бумаг','control'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение необычных операций (сделок), совокупности подозрительных операций и (или) действий, в том числе при осуществлении Банком профессиональной деятельности на рынке ценных бумаг, которые могут привести к потере Банком своей деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Отдела мониторинга операций клиентов физических лиц','methodology'),
    ('Осуществление выявления новых типов сомнительных финансовых схем, направленных на легализацию преступных доходов, или финансирование терроризма в части, касающейся деятельности Отдела мониторинга операций клиентов физических лиц','analytical'),
    ('Осуществление подготовки аналитических заключений по результатам оценки (анализа) операций (сделок) клиентов для Руководителя в целях квалификации необычных операций (сделок) клиентов (обычные или подозрительные)','analytical'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по вопросам, входящим в компетенцию Отдела мониторинга операций клиентов физических лиц','methodology'),
    ('Осуществление согласования платежей клиентов Банка с признаками сомнительности','control'),
    ('Осуществление рассмотрения обращений структурных бизнес-подразделений Банка по согласованию индивидуальных тарифов клиентам Банка в целях минимизации риска проведения подозрительных операций (сделок) в части, касающейся деятельности Отдела мониторинга операций клиентов физических лиц','control'),
    ('Осуществление консультирования работников УФМ СЦ по вопросам формирования сообщений о подозрительных операциях в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.3.1' AND u.is_archived = false;